  <div class="manage-card">
    <div class="card-header">
      <h3><i class="bi bi-briefcase-fill"></i> Vos Annonces en Ligne</h3>
      <p>Suivez l'état de diffusion et l'attractivité de vos offres d'emploi actives.</p>
    </div>

    <div class="table-wrapper">
      <table class="jobs-table">
        <thead>
          <tr>
            <th>Intitulé du Poste</th>
            <th>Type de Contrat</th>
            <th>Localisation</th>
            <th>Candidatures Reçues</th>
            <th>Statut</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td class="job-title">Développeur Fullstack Angular/Node</td>
            <td>CDI</td>
            <td>Tunis, Tunisie</td>
            <td class="candidate-count"><i class="bi bi-people-fill"></i> 8 profils</td>
            <td><span class="status-badge bg-green">Actif</span></td>
          </tr>
          <tr>
            <td class="job-title">Ingénieur DevOps Cloud</td>
            <td>CDI / SIVP</td>
            <td>Ariana, Tunisie</td>
            <td class="candidate-count"><i class="bi bi-people-fill"></i> 6 profils</td>
            <td><span class="status-badge bg-green">Actif</span></td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
